for $r in sql('
SELECT ORG08_CS_COSTO.c_centro_costo , ORG08_CS_COSTO.d_centro_costo FROM ORG08_CS_COSTO WHERE ORG08_CS_COSTO.c_centro_costo = {#SOURCE:@cc}
')/ROWS/ROW

for $r in sql(' SELECT C20.c_centro_costo, sum(C20.n_valor) as valor FROM PER02_PERSONAL_EMP as P2 , LIQ19_LIQUIDACION as l19 , LIQ19_EJECUCIONES as e19 , LIQ99_LIQUIDACION as l99 , LIQ99_RECIBOS as R99 , LIQ20_TOT_LIQ_PER as l20 , LIQ20_CCOSTO_CONC as C20 , LIQ20_CONC_LIQ_PER as P20 , LIQ14_CONCEPTOS as l14 , LIQ96_CONCEPTOS as L96 WHERE l19.oi_empresa = {#PARAMIN:@oi_empresaFIL} AND P2.oi_empresa = {#PARAMIN:@oi_empresaFIL} AND l19.e_periodo = {#PARAMIN:@e_periodoFIL} {%? (#PARAMIN:@oi_liquidacionFIL!='') {% and l19.oi_liquidacion = {%= #PARAMIN:@oi_liquidacionFIL %} %} {% %} %} AND l99.c_estado = \'F\' AND P20.n_valor != 0 {%? (#PARAMIN:@agrupar='centro') {% and C20.c_centro_costo = {#SOURCE:@cc} %} {% %} %} {%? (#SOURCE:@oi_concepto!='') {% AND l14.oi_concepto = {#SOURCE:@oi_concepto} %} {% %} %} {%? (#SOURCE:@oi_tipo_concepto!='') {% AND l14.oi_tipo_concepto = {#SOURCE:@oi_tipo_concepto} %} {% %} %} {%? (#SOURCE:@oi_personal_emp!='') {% AND P2.oi_personal_emp = {#SOURCE:@oi_personal_emp} %} {% %} %} {%? (string(#LISTAPERS:ROWS/ROW/@id)!='') {% AND P2.oi_personal_emp in ({%=string(#LISTAPERS:ROWS/ROW/@id) %}) %} {% %} %}
AND l19.oi_liquidacion = e19.oi_liquidacion AND e19.oi_liquidacion_ddo = l99.oi_liquidacion_ddo AND l99.oi_liquidacion_ddo = R99.oi_liquidacion_ddo AND R99.e_numero_legajo = P2.e_numero_legajo AND R99.oi_tot_liq_per = l20.oi_tot_liq_per AND l20.oi_tot_liq_per = P20.oi_tot_liq_per AND P20.oi_concepto_ddo = L96.oi_concepto_ddo AND L96.c_concepto = l14.c_concepto AND P20.oi_conc_liq_per = C20.oi_conc_liq_per GROUP BY C20.c_centro_costo
')/ROWS/ROW
